import React, { useState, useEffect } from "react";
import { Link, useNavigate, useLocation } from "react-router-dom";
import SearchBar from "./SearchBar";
import { 
  FaUser, FaUpload, FaInfoCircle, FaHome, 
  FaGraduationCap, FaSignInAlt, FaUserPlus, 
  FaBars, FaTimes, FaSignOutAlt, FaBookmark,
  FaDownload, FaUserCircle, FaBell, FaCog
} from "react-icons/fa";
import "./Navbar.css";

const Navbar = () => {
  const [isMenuOpen, setIsMenuOpen] = useState(false);
  const [isScrolled, setIsScrolled] = useState(false);
  const [activeDropdown, setActiveDropdown] = useState(null);
  const [isLoggedIn, setIsLoggedIn] = useState(false);
  const [userData, setUserData] = useState(null);
  const [showUserMenu, setShowUserMenu] = useState(false);
  const [notifications, setNotifications] = useState([]);
  
  const navigate = useNavigate();
  const location = useLocation();

  // Check login status on mount and when location changes
  useEffect(() => {
    const token = localStorage.getItem('study_portal_token');
    const user = localStorage.getItem('user_data');
    
    setIsLoggedIn(!!token);
    if (user) {
      try {
        setUserData(JSON.parse(user));
      } catch (e) {
        console.error('Failed to parse user data');
      }
    }
  }, [location]);

  // Fetch notifications if logged in
  useEffect(() => {
    if (isLoggedIn) {
      // Mock notifications - replace with API call
      setNotifications([
        { id: 1, text: "New notes added in B.Tech", read: false },
        { id: 2, text: "Your download is ready", read: true },
        { id: 3, text: "New PYQs available", read: false },
      ]);
    }
  }, [isLoggedIn]);

  // Handle scroll effect
  useEffect(() => {
    const handleScroll = () => {
      setIsScrolled(window.scrollY > 10);
    };
    window.addEventListener("scroll", handleScroll);
    return () => window.removeEventListener("scroll", handleScroll);
  }, []);

  // Close mobile menu when route changes
  useEffect(() => {
    setIsMenuOpen(false);
    setActiveDropdown(null);
    setShowUserMenu(false);
  }, [location]);

  // Handle logout
  const handleLogout = () => {
    localStorage.removeItem('study_portal_token');
    localStorage.removeItem('user_data');
    setIsLoggedIn(false);
    setUserData(null);
    setShowUserMenu(false);
    navigate('/');
  };

  // Course dropdown items
  const courseItems = [
    { id: 1, name: "B.Tech", icon: "💻", path: "/courses/btech", description: "Engineering" },
    { id: 2, name: "BCA", icon: "📱", path: "/courses/bca", description: "Computer Applications" },
    { id: 3, name: "BBA", icon: "📊", path: "/courses/bba", description: "Business Administration" },
    { id: 4, name: "MBA", icon: "💼", path: "/courses/mba", description: "Master of Business" },
    { id: 5, name: "MCA", icon: "🎯", path: "/courses/mca", description: "Computer Applications" },
    { id: 6, name: "B.Com", icon: "💰", path: "/courses/bcom", description: "Commerce" },
    { id: 7, name: "BA", icon: "📚", path: "/courses/ba", description: "Arts" },
    { id: 8, name: "B.Sc", icon: "🔬", path: "/courses/bsc", description: "Science" },
  ];

  // User menu items
  const userMenuItems = [
    { name: "Profile", icon: <FaUserCircle />, path: "/profile" },
    { name: "My Downloads", icon: <FaDownload />, path: "/downloads" },
    { name: "Bookmarks", icon: <FaBookmark />, path: "/bookmarks" },
    { name: "Settings", icon: <FaCog />, path: "/settings" },
  ];

  // Main nav items
  const navItems = [
    { name: "Home", icon: <FaHome />, path: "/" },
    { name: "Courses", icon: <FaGraduationCap />, path: null, dropdown: true },
    { name: "Upload", icon: <FaUpload />, path: "/upload" },
    { name: "About", icon: <FaInfoCircle />, path: "/about" },
  ];

  // Handle dropdown toggle
  const toggleDropdown = (dropdown) => {
    setActiveDropdown(activeDropdown === dropdown ? null : dropdown);
  };

  // Handle click outside to close dropdowns
  useEffect(() => {
    const handleClickOutside = (event) => {
      if (!event.target.closest('.dropdown-wrapper') && !event.target.closest('.user-menu-wrapper')) {
        setActiveDropdown(null);
        setShowUserMenu(false);
      }
    };
    document.addEventListener('click', handleClickOutside);
    return () => document.removeEventListener('click', handleClickOutside);
  }, []);

  return (
    <nav className={`navbar ${isScrolled ? "scrolled" : ""}`}>
      <div className="nav-container">
        
        {/* Logo */}
        <Link to="/" className="logo" onClick={() => setActiveDropdown(null)}>
          <div className="logo-icon">📚</div>
          <div className="logo-text">
            <span className="logo-title">Study Portal</span>
            <span className="logo-subtitle">by Karan</span>
          </div>
        </Link>

        {/* Desktop Navigation */}
        <div className="desktop-nav">
          {navItems.map((item) => (
            item.dropdown ? (
              <div 
                key={item.name}
                className="nav-item dropdown-wrapper"
                onMouseEnter={() => setActiveDropdown('courses')}
                onMouseLeave={() => setActiveDropdown(null)}
              >
                <div 
                  className={`nav-link ${activeDropdown === 'courses' ? 'active' : ''}`}
                  onClick={() => toggleDropdown('courses')}
                >
                  <span className="nav-icon">{item.icon}</span>
                  {item.name}
                  <span className="dropdown-arrow">▼</span>
                </div>
                
                <div className={`dropdown-content ${activeDropdown === 'courses' ? 'show' : ''}`}>
                  <div className="dropdown-grid">
                    {courseItems.map((course) => (
                      <Link 
                        key={course.id} 
                        to={course.path}
                        className="dropdown-item"
                        onClick={() => setActiveDropdown(null)}
                      >
                        <span className="course-icon">{course.icon}</span>
                        <div>
                          <div className="course-name">{course.name}</div>
                          <div className="course-desc">{course.description}</div>
                        </div>
                      </Link>
                    ))}
                  </div>
                  <div className="dropdown-footer">
                    <Link to="/courses" className="view-all-courses">
                      View All Courses →
                    </Link>
                  </div>
                </div>
              </div>
            ) : (
              <Link
                key={item.name}
                to={item.path}
                className={`nav-link ${location.pathname === item.path ? 'active' : ''}`}
                onClick={() => setActiveDropdown(null)}
              >
                <span className="nav-icon">{item.icon}</span>
                {item.name}
              </Link>
            )
          ))}

          {/* Search Bar */}
          <div className="search-wrapper">
            <SearchBar />
          </div>

          {/* Auth Section */}
          <div className="auth-section">
            {isLoggedIn ? (
              <div className="user-menu-wrapper">
                {/* Notifications */}
                <div className="notifications-wrapper">
                  <button 
                    className="notification-btn"
                    onClick={() => toggleDropdown('notifications')}
                  >
                    <FaBell />
                    {notifications.filter(n => !n.read).length > 0 && (
                      <span className="notification-badge">
                        {notifications.filter(n => !n.read).length}
                      </span>
                    )}
                  </button>
                  
                  <div className={`notifications-dropdown ${activeDropdown === 'notifications' ? 'show' : ''}`}>
                    {notifications.length > 0 ? (
                      <>
                        {notifications.map(notif => (
                          <div key={notif.id} className={`notification-item ${!notif.read ? 'unread' : ''}`}>
                            <p>{notif.text}</p>
                            <span className="notification-time">2 min ago</span>
                          </div>
                        ))}
                        <div className="notifications-footer">
                          <button onClick={() => navigate('/notifications')}>
                            View All
                          </button>
                        </div>
                      </>
                    ) : (
                      <div className="no-notifications">No new notifications</div>
                    )}
                  </div>
                </div>

                {/* User Menu */}
                <div className="user-menu">
                  <button 
                    className="user-menu-btn"
                    onClick={() => setShowUserMenu(!showUserMenu)}
                  >
                    {userData?.avatar ? (
                      <img src={userData.avatar} alt="user" className="user-avatar" />
                    ) : (
                      <FaUserCircle className="user-icon" />
                    )}
                    <span className="user-name">
                      {userData?.name?.split(' ')[0] || 'User'}
                    </span>
                  </button>
                  
                  <div className={`user-dropdown ${showUserMenu ? 'show' : ''}`}>
                    {userMenuItems.map(item => (
                      <Link 
                        key={item.name}
                        to={item.path}
                        className="user-dropdown-item"
                        onClick={() => setShowUserMenu(false)}
                      >
                        <span className="item-icon">{item.icon}</span>
                        {item.name}
                      </Link>
                    ))}
                    <div className="dropdown-divider"></div>
                    <button 
                      onClick={handleLogout}
                      className="user-dropdown-item logout"
                    >
                      <FaSignOutAlt className="item-icon" />
                      Logout
                    </button>
                  </div>
                </div>
              </div>
            ) : (
              <>
                <button 
                  onClick={() => navigate("/login")} 
                  className="auth-btn login-btn"
                >
                  <FaSignInAlt className="btn-icon" />
                  <span>Login</span>
                </button>
                <button 
                  onClick={() => navigate("/register")} 
                  className="auth-btn register-btn"
                >
                  <FaUserPlus className="btn-icon" />
                  <span>Register</span>
                </button>
              </>
            )}
          </div>
        </div>

        {/* Mobile Menu Button */}
        <button
          className="mobile-menu-btn"
          onClick={() => setIsMenuOpen(!isMenuOpen)}
          aria-label="Toggle menu"
        >
          {isMenuOpen ? <FaTimes /> : <FaBars />}
        </button>
      </div>

      {/* Mobile Navigation */}
      <div className={`mobile-nav ${isMenuOpen ? "open" : ""}`}>
        <div className="mobile-nav-header">
          <div className="mobile-logo">
            <span className="logo-icon-small">📚</span>
            <h3>Study Portal</h3>
          </div>
          <button 
            className="close-menu-btn"
            onClick={() => setIsMenuOpen(false)}
          >
            <FaTimes />
          </button>
        </div>

        {isLoggedIn && (
          <div className="mobile-user-info">
            <FaUserCircle className="mobile-user-icon" />
            <div>
              <div className="mobile-user-name">{userData?.name || 'User'}</div>
              <div className="mobile-user-email">{userData?.email || 'user@example.com'}</div>
            </div>
          </div>
        )}

        <div className="mobile-nav-links">
          {navItems.map((item) => (
            item.dropdown ? (
              <div key={item.name} className="mobile-dropdown">
                <div 
                  className="mobile-nav-link"
                  onClick={() => toggleDropdown('courses-mobile')}
                >
                  <span className="nav-icon">{item.icon}</span>
                  {item.name}
                  <span className="dropdown-arrow">
                    {activeDropdown === 'courses-mobile' ? '▲' : '▼'}
                  </span>
                </div>
                
                <div className={`mobile-dropdown-content ${activeDropdown === 'courses-mobile' ? 'show' : ''}`}>
                  {courseItems.map((course) => (
                    <Link 
                      key={course.id} 
                      to={course.path}
                      className="mobile-dropdown-item"
                      onClick={() => setIsMenuOpen(false)}
                    >
                      <span className="course-icon">{course.icon}</span>
                      <div>
                        <div>{course.name}</div>
                        <small>{course.description}</small>
                      </div>
                    </Link>
                  ))}
                </div>
              </div>
            ) : (
              <Link
                key={item.name}
                to={item.path}
                className={`mobile-nav-link ${location.pathname === item.path ? 'active' : ''}`}
                onClick={() => setIsMenuOpen(false)}
              >
                <span className="nav-icon">{item.icon}</span>
                {item.name}
              </Link>
            )
          ))}

          {/* User menu items for mobile */}
          {isLoggedIn && userMenuItems.map(item => (
            <Link
              key={item.name}
              to={item.path}
              className="mobile-nav-link"
              onClick={() => setIsMenuOpen(false)}
            >
              <span className="nav-icon">{item.icon}</span>
              {item.name}
            </Link>
          ))}

          {/* Mobile Search */}
          <div className="mobile-search">
            <SearchBar />
          </div>

          {/* Mobile Auth Buttons */}
          {!isLoggedIn ? (
            <div className="mobile-auth">
              <button 
                onClick={() => {
                  navigate("/login");
                  setIsMenuOpen(false);
                }} 
                className="mobile-auth-btn login"
              >
                <FaSignInAlt />
                Login
              </button>
              <button 
                onClick={() => {
                  navigate("/register");
                  setIsMenuOpen(false);
                }} 
                className="mobile-auth-btn register"
              >
                <FaUserPlus />
                Register
              </button>
            </div>
          ) : (
            <div className="mobile-auth">
              <button 
                onClick={handleLogout}
                className="mobile-auth-btn logout"
              >
                <FaSignOutAlt />
                Logout
              </button>
            </div>
          )}
        </div>

        <div className="mobile-nav-footer">
          <p>© 2024 Study Portal by Karan</p>
        </div>
      </div>

      {/* Overlay for mobile menu */}
      {isMenuOpen && (
        <div className="mobile-overlay" onClick={() => setIsMenuOpen(false)}></div>
      )}
    </nav>
  );
};

export default Navbar;
